package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.ControleRszKwartaalGrensVrijwilligeBrandweer;
import be.schaubroeck.lpb.rkm.rekenmotor.rsz.WerknemersKengetalFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.Rszppo;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Quarter;
import com.google.common.collect.ImmutableList;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

import java.util.HashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.stream.Collectors;

@AllArgsConstructor
public class ControleRszKwartaalGrensVrijwilligeBrandweerDmfappl implements ControleRszKwartaalGrensVrijwilligeBrandweer {

    private final ConstantManager constantManager;

    private static boolean isRegul(Set<OpdrachtDatumLoonCodeKey> voorkomenCode, int fouteCode) {
        for (OpdrachtDatumLoonCodeKey key : voorkomenCode) {
            if (key.getLoonCode() == fouteCode) {
                return true;
            }
        }
        return false;
    }

    public void controleer(
            Persoon persoon, RekenTijd rekenTijd, LoonElementManager manager, List<RekenHoofd> kwartaalResultaten,
            List<Opdracht> opdrachtenKwartaal, RegulManager regulManager) {
        Money grens = constantManager.getActualConstant(Konstanten.KST_GRENS_RSZ_VRIJW_BRW, rekenTijd).getMoney();

        Map<Integer, Opdracht> opdrachtMap = persoon.getOpdrachten().stream()
                .collect(Collectors.toMap(Opdracht::getId, x -> x));

        Set<OpdrachtDatumLoonCodeKey> voorkomenCode = new HashSet<>();
        Money basis = SocialeBijdragenDmfapplVrijwilligeBrandweer.getBasis(rekenTijd, manager, kwartaalResultaten, voorkomenCode, opdrachtMap);

        int fouteCode = SocialeBijdragenDmfapplVrijwilligeBrandweer.getFouteCode(grens, basis);
        boolean regul = isRegul(voorkomenCode, fouteCode);

        if (regul) {
            controleGrensVrijeBrandweerRegul(persoon, rekenTijd, kwartaalResultaten, opdrachtenKwartaal, regulManager, grens, opdrachtMap, basis);
        }
    }

    private void controleGrensVrijeBrandweerRegul(
            Persoon persoon, RekenTijd rekenTijd, List<RekenHoofd> kwartaalResultaten, List<Opdracht> opdrachtenKwartaal, RegulManager regulManager, Money grens,
            Map<Integer, Opdracht> opdrachtMap, Money basis) {
        Set<Integer> opdrachtids = new HashSet<>();
        for (RekenHoofd rekenHoofd : kwartaalResultaten) {
            Opdracht opdracht = opdrachtMap.get(rekenHoofd.getOpdracht().getId());
            if (opdracht != null) {
                Opper opper = RekenTools.getLaatsteGegevens(opdracht.getOpperSlices());
                Rszppo rszppo = opper.getRszppo();
                if (WerknemersKengetalFactory.isVrijwilligeBrandweer(rekenTijd, rekenHoofd.getWerknemersKengetal(), rszppo.getStatuutDmfappl())) {
                    Integer id = opdracht.getId();
                    opdrachtids.add(id);
                }
            }
        }
        persoon.getOpdrachten().stream()
                .filter(opdracht -> SocialeBijdragenDmfapplVrijwilligeBrandweer.isOpdrachtVrijwilligeBrandweer(rekenTijd, opdracht))
                .map(Opdracht::getId)
                .forEach(opdrachtids::add);

        opdrachtenKwartaal = opdrachtenKwartaal.stream()
                .filter(opdracht -> opdrachtids.contains(opdracht.getId()))
                .collect(Collectors.toList());

        Regulkode regulKode = basis.compareTo(grens) <= 0 ? Regulkode.LOONKODE_942_FOUT_GEBRUIK : Regulkode.LOONKODE_542_FOUT_GEBRUIK;
        activeerRegulVoorKwartaalOpdrachten(rekenTijd, opdrachtenKwartaal, regulManager, regulKode, true);
    }

    protected void activeerRegulVoorKwartaalOpdrachten(
            RekenTijd rekenTijd, List<Opdracht> opdrachtenKwartaal, RegulManager regulManager, Regulkode regulKode, boolean currentMonth) {
        Quarter kwartaal = new Quarter(rekenTijd.beginDatum);
        List<LocalDate> kwartaalDatums = ImmutableList.of(kwartaal.getStart(), kwartaal.getStart().plusMonths(1), kwartaal.getStart().plusMonths(2));
        for (Opdracht opdracht : opdrachtenKwartaal) {
            LocalDateInterval periode = new LocalDateInterval(opdracht.getBeginDatum(), opdracht.getEindDatum());
            for (LocalDate beginDatum : kwartaalDatums) {
                if (periode.contains(beginDatum) && (currentMonth || !beginDatum.equals(rekenTijd.beginDatum))) {
                    regulManager.addRegul(beginDatum, opdracht, regulKode);
                }
            }
        }
    }
}
